noncompliant:
// Noncompliant: old style hex escape sequences
char oldHex = '\x40';  // @ character
std::string oldHexStr = "\x48\x65\x6C\x6C\x6F";  // Hello

// Noncompliant: old style octal escape sequences
char oldOctal = '\100';  // @ character

// Noncompliant: old style unicode escape sequences
wchar_t oldUnicode = L'\u0040';  // @ character
std::wstring oldUnicodeStr = L"\u0048\u0065\u006C\u006C\u006F";  // Hello

compliant:
// Compliant: C++23 delimited hex escape sequences
char newHex = '\x{40}';  // @ character
std::string newHexStr = "\x{48}\x{65}\x{6C}\x{6C}\x{6F}";  // Hello

// Compliant: delimited octal escape sequences
char newOctal = '\o{100}';  // @ character

// Compliant: delimited unicode escape sequences
wchar_t newUnicode = L'\u{0040}';  // @ character
std::wstring newUnicodeStr = L"\u{0048}\u{0065}\u{006C}\u{006C}\u{006F}";  // Hello

// Compliant: direct character representation when possible
char direct = '@';
std::string directStr = "Hello";
